#include <stdio.h>
#include <ctype.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        char ch;
        scanf(" %c", &ch); // skip any whitespace
        ch = tolower((unsigned char)ch);
        if (ch == 'a' || ch == 'e' || ch == 'i' || ch == 'o' || ch == 'u') {
            printf("True
");
        } else {
            printf("False
");
        }
    }
    return 0;
}

